SELECT log_id, username, operation, ip, create_time, status
FROM system_logs


        AND username LIKE CONCAT('%', #{username}, '%')


        AND create_time >= #{startDate}


        AND create_time <= #{endDate}


ORDER BY create_time DESC
LIMIT #{offset}, #{size}

